import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const countryCodes = [
  { code: "+1", label: "🇺🇸 USA", value: "+1" },
  { code: "+44", label: "🇬🇧 UK", value: "+44" },
  { code: "+91", label: "🇮🇳 India", value: "+91" },
  { code: "+61", label: "🇦🇺 Australia", value: "+61" },
  { code: "+81", label: "🇯🇵 Japan", value: "+81" },
  { code: "+49", label: "🇩🇪 Germany", value: "+49" },
  { code: "+33", label: "🇫🇷 France", value: "+33" },
  { code: "+86", label: "🇨🇳 China", value: "+86" },
];

export default function Register({ onRegister }) {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    firstName: "",
    lastName: "",
    email: "",
    address: "",
    phone: "",
  });
  const [selectedCountryCode, setSelectedCountryCode] = useState("+91");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000";

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name === "phone") {
      if (/^\d*$/.test(value)) {
        setForm({ ...form, [name]: value });
      }
    } else {
      setForm({ ...form, [name]: value });
    }
  };

  const handleSubmit = async () => {
    if (!form.firstName || !form.lastName || !form.email || !form.address || !form.phone) {
      setError("Please fill in all required fields");
      return;
    }

    // Basic email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(form.email)) {
      setError("Please enter a valid email address");
      return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const fullPhone = selectedCountryCode + form.phone;
      const res = await fetch(`${API_BASE}/api/auth/register`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: `${form.firstName} ${form.lastName}`,
          email: form.email,
          address: form.address,
          phone: fullPhone
        }),
      });

      const data = await res.json();
      if (res.ok && data.success) {
        setSuccess("Account created successfully! 🎉");
        setTimeout(() => {
          onRegister(data.user);
        }, 2000);
      } else {
        setError(data.message || "Registration failed");
      }
    } catch (e) {
      setError("Network error. Please try again.");
    }
    setLoading(false);
  };

  return (
    <div className="register-page">
      {/* Cartoon Characters */}
      <div className="cartoon-left">
        <div className="character pointing">
          <div className="character-body">
            <div className="character-head">👨‍💻</div>
            <div className="character-arm pointing-arm">👈</div>
          </div>
        </div>
      </div>

      <div className="cartoon-right">
        <div className="character sitting">
          <div className="character-body">
            <div className="character-head">👩‍💻</div>
            <div className="laptop">💻</div>
          </div>
        </div>
        <div className="leaf-decoration">🍃</div>
      </div>

      <div className="register-container">
        <div className="register-card">
          {/* Profile Icon */}
          <div className="profile-icon-container">
            <div className="profile-icon">👤</div>
          </div>

          <h1 className="register-title">Join Smart Home</h1>
          <p className="register-subtitle">Create your account to get started</p>

          <div className="register-form">
            {/* Two Column Layout */}
            <div className="form-row">
              <div className="form-group">
                <label>First Name</label>
                <input
                  type="text"
                  name="firstName"
                  placeholder="John"
                  value={form.firstName}
                  onChange={handleChange}
                  className="form-input"
                />
              </div>
              <div className="form-group">
                <label>Last Name</label>
                <input
                  type="text"
                  name="lastName"
                  placeholder="Doe"
                  value={form.lastName}
                  onChange={handleChange}
                  className="form-input"
                />
              </div>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  name="email"
                  placeholder="john@example.com"
                  value={form.email}
                  onChange={handleChange}
                  className="form-input"
                />
              </div>
              <div className="form-group">
                <label>Phone Number</label>
                <div className="phone-input-group">
                  <select
                    value={selectedCountryCode}
                    onChange={(e) => setSelectedCountryCode(e.target.value)}
                    className="country-select"
                  >
                    {countryCodes.map((country) => (
                      <option key={country.code} value={country.code}>
                        {country.label}
                      </option>
                    ))}
                  </select>
                  <input
                    type="text"
                    name="phone"
                    placeholder="Enter phone number"
                    value={form.phone}
                    onChange={handleChange}
                    className="phone-input"
                    maxLength="10"
                  />
                </div>
              </div>
            </div>

            <div className="form-group full-width">
              <label>Address</label>
              <input
                type="text"
                name="address"
                placeholder="Enter your full address"
                value={form.address}
                onChange={handleChange}
                className="form-input"
              />
            </div>

            <button
              onClick={handleSubmit}
              disabled={loading}
              className="submit-button"
            >
              {loading ? (
                <span className="button-content">
                  <div className="spinner"></div>
                  Creating Account...
                </span>
              ) : (
                "SUBMIT"
              )}
            </button>
          </div>

          {error && (
            <div className="alert error">
              <span className="alert-icon">⚠️</span>
              {error}
            </div>
          )}

          {success && (
            <div className="alert success">
              <span className="alert-icon">✅</span>
              {success}
            </div>
          )}

          <div className="register-footer">
            <p>Already have an account? <button className="link-button" onClick={() => navigate('/login')}>Sign In</button></p>
          </div>
        </div>
      </div>
    </div>
  );
}
